def longest_common_subsequence(s1, s2):
    m = len(s1)
    n = len(s2)
    matrix = [[0] * n for _ in range(m)]
    for i in range(m):
        for j in range(n):
            if s1[i] == s2[j]:
                matrix[i][j] = matrix[i + 1][j + 1] + 1
            else:
                matrix[i][j] = max(matrix[i][j + 1], matrix[i + 1][j])
    lcs = []
    i = m - 1
    j = n - 1
    while i >= 0 and j >= 0:
        if s1[i] == s2[j]:
            lcs.append(s1[i])
            i -= 1
            j -= 1
        elif matrix[i][j] == matrix[i + 1][j]:
            i -= 1
        else:
            j -= 1
    return ''.join(reversed(lcs))

def binary_search(arr, target):
    left = 0
    right = len(arr) - 1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        if arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return -1

