class Queue:
    def __init__(self):
        self.stack1 = []
        self.stack2 = []

    def is_empty(self):
        return not self.stack1 or not self.stack2

    def enqueue(self, element):
        if not self.stack1:
            self.stack1.append(element)
        else:
            self.stack2.append(element)

    def dequeue(self):
        if self.stack1 and self.stack2:
            self.stack1.pop()
            self.stack2.pop()
        elif self.stack1:
            self.stack1.pop()
        else:
            self.stack2.pop()

    def peek(self):
        if self.stack1 and self.stack2:
            return self.stack2[-1]
        elif self.stack1:
            return self.stack1[-1]
        else:
            return self.stack2[-1]

    def __str__(self):
        if self.is_empty():
            return "Queue is empty."
        elif len(self.stack1) == len(self.stack2):
            return f"Queue contains {len(self.stack1)} elements: {self.stack1}"
        else:
            return f"Queue contains {len(self.stack1)} elements: {self.stack1}, {len(self.stack2)} elements: {self.stack2}"
